xkb_keymap {
    // Include your existing system components
    xkb_keycodes  { include "evdev+aliases(qwerty)" };
    xkb_types     { include "complete" };
    xkb_compat    { include "complete" };

    // The logic: Map Caps Lock to the Control symbol
    xkb_symbols   {
        include "pc+us+inet(evdev)"
        include "shift(both_capslock)"
        include "compose(menu)"

        // This is the core remap
        key <CAPS> { [ Control_L, Control_L ] };

        // This ensures the modifier bit is correctly set
        modifier_map Control { <CAPS> };
    };

    xkb_geometry  { include "pc(pc105)" };
};
